export const meta = {
  name: 'create-rootable-avd-sdk36',
  description: 'Explore, create and verify a rootable Android AVD with SDK 36',
  phases: [
    { title: 'Research', detail: 'Investigate requirements for rootable AVD' },
    { title: 'Environment Check', detail: 'Verify SDK tools and system images' },
    { title: 'AVD Creation', detail: 'Create AVD with rootable system image' },
    { title: 'Verification', detail: 'Start AVD and verify adb root works' }
  ]
}

phase('Research')
log('Phase 1: Researching requirements for rootable Android AVD with SDK 36')

const researchSchema = {
  type: 'object',
  properties: {
    key_requirements: {
      type: 'array',
      items: { type: 'string' },
      description: 'Key requirements for creating a rootable AVD'
    },
    system_image_type: {
      type: 'string',
      description: 'Recommended system image type (e.g., google_apis, google_apis_playstore, default)'
    },
    abi_recommendation: {
      type: 'string',
      description: 'Recommended ABI architecture'
    },
    critical_notes: {
      type: 'array',
      items: { type: 'string' },
      description: 'Critical notes about rootable AVDs'
    }
  },
  required: ['key_requirements', 'system_image_type', 'abi_recommendation', 'critical_notes']
}

const research = await agent(
  `Research how to create an Android AVD with SDK 36 (Android 15) that supports adb root.

Key questions to answer:
1. What type of system image is required? (google_apis vs google_apis_playstore vs default)
2. Why do some AVDs not support adb root?
3. What are the specific package names for SDK 36 system images?
4. What commands are needed to check available images and create AVD?
5. Any special configuration needed for root access?

Use web search to find current information about Android SDK 36 and rootable AVDs.`,
  { schema: researchSchema, phase: 'Research' }
)

if (!research) {
  throw new Error('Research phase failed')
}

log(`Research complete: ${research.system_image_type} system image required`)

phase('Environment Check')
log('Phase 2: Checking Android SDK environment and available system images')

const envCheckSchema = {
  type: 'object',
  properties: {
    sdk_path: {
      type: 'string',
      description: 'Path to Android SDK'
    },
    sdkmanager_available: {
      type: 'boolean',
      description: 'Whether sdkmanager is available'
    },
    avdmanager_available: {
      type: 'boolean',
      description: 'Whether avdmanager is available'
    },
    adb_available: {
      type: 'boolean',
      description: 'Whether adb is available'
    },
    emulator_available: {
      type: 'boolean',
      description: 'Whether emulator binary is available'
    },
    sdk36_images_installed: {
      type: 'array',
      items: { type: 'string' },
      description: 'List of SDK 36 system images already installed'
    },
    recommended_image_package: {
      type: 'string',
      description: 'Recommended system image package to install for rootable AVD'
    },
    installation_needed: {
      type: 'boolean',
      description: 'Whether system image installation is needed'
    }
  },
  required: ['sdkmanager_available', 'avdmanager_available', 'adb_available', 'sdk36_images_installed', 'recommended_image_package', 'installation_needed']
}

const envCheck = await agent(
  `Check the Android SDK environment and system images for SDK 36.

Tasks:
1. Locate Android SDK (check ANDROID_HOME, ANDROID_SDK_ROOT, common paths)
2. Verify sdkmanager, avdmanager, adb, and emulator binaries exist
3. List all installed system images using 'sdkmanager --list_installed'
4. Check available SDK 36 images using 'sdkmanager --list'
5. Based on research findings (system image type: ${research.system_image_type}), identify the exact package to install
6. Determine if installation is needed

Expected package format: system-images;android-36;<type>;<abi>
where <type> should be '${research.system_image_type}' and <abi> is likely x86_64 or arm64-v8a`,
  { schema: envCheckSchema, phase: 'Environment Check' }
)

if (!envCheck) {
  throw new Error('Environment check failed')
}

if (!envCheck.sdkmanager_available || !envCheck.avdmanager_available || !envCheck.adb_available) {
  throw new Error('Required Android SDK tools are not available')
}

log(`Environment check complete. Installation needed: ${envCheck.installation_needed}`)

phase('AVD Creation')
log('Phase 3: Creating rootable AVD with SDK 36')

const avdCreationSchema = {
  type: 'object',
  properties: {
    installation_performed: {
      type: 'boolean',
      description: 'Whether system image installation was performed'
    },
    installation_success: {
      type: 'boolean',
      description: 'Whether installation succeeded (if performed)'
    },
    avd_name: {
      type: 'string',
      description: 'Name of the created AVD'
    },
    avd_created: {
      type: 'boolean',
      description: 'Whether AVD was successfully created'
    },
    device_profile: {
      type: 'string',
      description: 'Device profile used for AVD'
    },
    system_image_used: {
      type: 'string',
      description: 'Full system image package used'
    },
    creation_command: {
      type: 'string',
      description: 'Command used to create AVD'
    }
  },
  required: ['avd_created', 'avd_name', 'system_image_used']
}

const avdCreation = await agent(
  `Create a rootable Android AVD with SDK 36.

Steps:
1. If installation needed (${envCheck.installation_needed}), install the system image:
   - Package: ${envCheck.recommended_image_package}
   - Use: yes | sdkmanager "${envCheck.recommended_image_package}"

2. List available device profiles: avdmanager list device
   - Choose a suitable device (e.g., pixel_6, pixel_5, or other modern device)

3. Create AVD with a descriptive name (e.g., 'rootable_sdk36_x86_64'):
   - Use: avdmanager create avd -n <name> -k "${envCheck.recommended_image_package}" -d <device_profile>
   - Add -f flag if AVD with same name exists

4. Verify AVD was created: avdmanager list avd

Important: Use the exact system image package from environment check.`,
  { schema: avdCreationSchema, phase: 'AVD Creation' }
)

if (!avdCreation || !avdCreation.avd_created) {
  throw new Error('AVD creation failed')
}

log(`AVD '${avdCreation.avd_name}' created successfully`)

phase('Verification')
log('Phase 4: Starting AVD and verifying adb root functionality')

const verificationSchema = {
  type: 'object',
  properties: {
    emulator_started: {
      type: 'boolean',
      description: 'Whether emulator started successfully'
    },
    boot_completed: {
      type: 'boolean',
      description: 'Whether emulator finished booting'
    },
    adb_connected: {
      type: 'boolean',
      description: 'Whether adb could connect to emulator'
    },
    adb_root_available: {
      type: 'boolean',
      description: 'Whether adb root command is available'
    },
    adb_root_successful: {
      type: 'boolean',
      description: 'Whether adb root executed successfully'
    },
    root_verification_output: {
      type: 'string',
      description: 'Output from adb root command and verification'
    },
    shell_uid: {
      type: 'string',
      description: 'UID from adb shell id command (should be 0 for root)'
    },
    final_verdict: {
      type: 'string',
      enum: ['SUCCESS', 'FAILED'],
      description: 'Final verification result'
    },
    failure_reason: {
      type: 'string',
      description: 'Reason for failure if verification failed'
    }
  },
  required: ['emulator_started', 'adb_root_available', 'adb_root_successful', 'final_verdict']
}

const verification = await agent(
  `Start the AVD '${avdCreation.avd_name}' and verify adb root works.

Steps:
1. Start emulator in background with no-window and no-audio:
   - Use: emulator -avd ${avdCreation.avd_name} -no-window -no-audio -no-boot-anim &
   - Give it a unique name to kill later

2. Wait for device to be ready:
   - Use: adb wait-for-device
   - Then check boot completion: adb shell getprop sys.boot_completed
   - Poll until it returns '1' (max ~120 seconds)

3. Execute adb root:
   - Run: adb root
   - Capture output

4. Verify root access:
   - Run: adb shell id
   - Should show uid=0(root)
   - Run: adb shell whoami
   - Should show 'root'

5. Test root functionality:
   - Try: adb shell "su -c 'id'"
   - Or: adb remount (should succeed if root works)

6. Determine final verdict:
   - SUCCESS if adb root works and uid=0
   - FAILED otherwise with reason

7. Cleanup:
   - Kill emulator process: adb emu kill

Important: Wait adequately for boot completion before testing root.`,
  { schema: verificationSchema, phase: 'Verification' }
)

if (!verification) {
  throw new Error('Verification phase failed')
}

log(`Verification complete: ${verification.final_verdict}`)

// Return comprehensive results
return {
  success: verification.final_verdict === 'SUCCESS',
  research_findings: {
    system_image_type: research.system_image_type,
    key_requirements: research.key_requirements,
    critical_notes: research.critical_notes
  },
  environment: {
    sdk_path: envCheck.sdk_path,
    tools_available: {
      sdkmanager: envCheck.sdkmanager_available,
      avdmanager: envCheck.avdmanager_available,
      adb: envCheck.adb_available,
      emulator: envCheck.emulator_available
    },
    system_image_package: envCheck.recommended_image_package
  },
  avd_details: {
    name: avdCreation.avd_name,
    device_profile: avdCreation.device_profile,
    system_image: avdCreation.system_image_used,
    creation_command: avdCreation.creation_command
  },
  verification_results: {
    emulator_started: verification.emulator_started,
    boot_completed: verification.boot_completed,
    adb_root_available: verification.adb_root_available,
    adb_root_successful: verification.adb_root_successful,
    shell_uid: verification.shell_uid,
    verdict: verification.final_verdict,
    details: verification.root_verification_output,
    failure_reason: verification.failure_reason
  }
}

export const meta = {
  name: 'explore-all-sdk36-images',
  description: 'Deep exploration of all SDK 36 system images to find rootable options',
  phases: [
    { title: 'List All Images', detail: 'Find all available SDK 36 system images' },
    { title: 'Test Each Image', detail: 'Create and test each available image type' },
    { title: 'Alternative Solutions', detail: 'Explore workarounds or older SDK versions' }
  ]
}

phase('List All Images')
log('Phase 1: Listing all available SDK 36 system images')

const listSchema = {
  type: 'object',
  properties: {
    all_sdk36_images: {
      type: 'array',
      items: { type: 'string' },
      description: 'All system-images;android-36;* packages found'
    },
    installed_images: {
      type: 'array',
      items: { type: 'string' },
      description: 'Already installed SDK 36 images'
    },
    available_to_install: {
      type: 'array',
      items: { type: 'string' },
      description: 'SDK 36 images available for installation'
    },
    non_playstore_images: {
      type: 'array',
      items: { type: 'string' },
      description: 'Images without playstore (potential rootable candidates)'
    }
  },
  required: ['all_sdk36_images', 'non_playstore_images']
}

const imageList = await agent(
  `List ALL available system images for SDK 36 (Android 15).

Tasks:
1. Run: sdkmanager --list | grep "system-images;android-36"
2. Identify all variants: default, google_apis, google_apis_playstore, android-tv, android-wear, etc.
3. Check which are already installed: sdkmanager --list_installed | grep "android-36"
4. Filter out google_apis_playstore variants (known production builds)
5. List all potential rootable candidates

Include full package names like: system-images;android-36;<type>;<abi>`,
  { schema: listSchema, phase: 'List All Images' }
)

if (!imageList || imageList.all_sdk36_images.length === 0) {
  log('No SDK 36 images found, will explore alternatives')
  throw new Error('No SDK 36 system images available')
}

log(`Found ${imageList.all_sdk36_images.length} SDK 36 images, ${imageList.non_playstore_images.length} non-playstore variants`)

phase('Test Each Image')
log('Phase 2: Testing each non-playstore image for root capability')

// Test each candidate image
const testResults = []

for (let i = 0; i < imageList.non_playstore_images.length; i++) {
  const imagePackage = imageList.non_playstore_images[i]

  const testSchema = {
    type: 'object',
    properties: {
      image_package: { type: 'string' },
      installed: { type: 'boolean' },
      avd_created: { type: 'boolean' },
      emulator_started: { type: 'boolean' },
      build_type: { type: 'string', description: 'user, userdebug, or eng' },
      debuggable: { type: 'string', description: 'ro.debuggable property value' },
      adb_root_works: { type: 'boolean' },
      root_test_output: { type: 'string' },
      verdict: { type: 'string', enum: ['ROOTABLE', 'NOT_ROOTABLE', 'ERROR'] }
    },
    required: ['image_package', 'verdict']
  }

  log(`Testing image ${i + 1}/${imageList.non_playstore_images.length}: ${imagePackage}`)

  const testResult = await agent(
    `Test if system image '${imagePackage}' supports adb root.

Steps:
1. Install if not already: yes | sdkmanager "${imagePackage}"
2. Create temporary AVD: avdmanager create avd -n test_root_${i} -k "${imagePackage}" -d pixel_6 -f
3. Start emulator: emulator -avd test_root_${i} -no-window -no-audio -no-boot-anim &
4. Wait for boot: adb wait-for-device && poll for sys.boot_completed=1
5. Check build type: adb shell getprop ro.build.type
6. Check debuggable: adb shell getprop ro.debuggable
7. Test adb root: adb root
8. Check result: adb shell id
9. Cleanup: adb emu kill
10. Delete AVD: avdmanager delete avd -n test_root_${i}

Verdict:
- ROOTABLE if adb root succeeds and uid=0
- NOT_ROOTABLE if production build error
- ERROR if other failures`,
    { schema: testSchema, phase: 'Test Each Image', label: `Test ${imagePackage}` }
  )

  if (testResult) {
    testResults.push(testResult)
    if (testResult.verdict === 'ROOTABLE') {
      log(`✓ FOUND ROOTABLE IMAGE: ${imagePackage}`)
    }
  }
}

const rootableImages = testResults.filter(r => r.verdict === 'ROOTABLE')

log(`Testing complete: ${rootableImages.length} rootable images found`)

phase('Alternative Solutions')
log('Phase 3: Exploring alternatives if no rootable SDK 36 found')

const alternativeSchema = {
  type: 'object',
  properties: {
    sdk36_rootable_found: { type: 'boolean' },
    rootable_image_package: { type: 'string' },
    alternatives_explored: { type: 'boolean' },
    older_sdk_versions: {
      type: 'array',
      items: { type: 'string' },
      description: 'List of older SDK versions with rootable images'
    },
    manual_root_method: { type: 'string', description: 'Manual rooting method if available' },
    recommendation: { type: 'string' }
  },
  required: ['sdk36_rootable_found', 'recommendation']
}

let alternatives = null

if (rootableImages.length === 0) {
  log('No rootable SDK 36 images found, exploring alternatives')

  alternatives = await agent(
    `No rootable SDK 36 images found. Explore alternatives:

1. Check SDK 35, 34, 33 for rootable images:
   - Run: sdkmanager --list | grep "system-images;android-3[345]"
   - Filter out playstore variants
   - Identify which have userdebug builds

2. Research manual rooting methods for SDK 36:
   - Web search: "Android 15 AVD root access"
   - Check for Magisk or SuperSU for emulator
   - Check for custom system images

3. Check if Google provides separate userdebug builds:
   - AOSP builds
   - Android source builds

4. Provide recommendation on best path forward`,
    { schema: alternativeSchema, phase: 'Alternative Solutions' }
  )
}

return {
  all_images_found: imageList.all_sdk36_images,
  non_playstore_candidates: imageList.non_playstore_images,
  test_results: testResults,
  rootable_images: rootableImages,
  alternatives: alternatives,
  final_recommendation: rootableImages.length > 0 
    ? `Use ${rootableImages[0].image_package} for rootable SDK 36 AVD`
    : alternatives?.recommendation || 'No rootable SDK 36 solution found'
}

